<template>
  <div class="system-logs-container">
    <el-card>
      <div slot="header" class="page-header">
        <span>系统日志管理</span>
        <div class="header-actions">
          <el-date-picker
            v-model="dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            :picker-options="pickerOptions"
            @change="handleDateChange"
          />
          <el-select v-model="logLevel" placeholder="日志级别" @change="handleLevelChange">
            <el-option label="全部" value="" />
            <el-option label="错误" value="ERROR" />
            <el-option label="警告" value="WARNING" />
            <el-option label="信息" value="INFO" />
            <el-option label="调试" value="DEBUG" />
          </el-select>
          <el-button type="primary" @click="fetchLogs">查询</el-button>
          <el-button type="danger" @click="showClearDialog = true">清除日志</el-button>
        </div>
      </div>
      
      <el-table
        :data="logs"
        style="width: 100%"
        v-loading="loading"
        border
      >
        <el-table-column prop="timestamp" label="时间" width="180">
          <template slot-scope="scope">
            {{ formatDate(scope.row.timestamp) }}
          </template>
        </el-table-column>
        <el-table-column prop="level" label="级别" width="100">
          <template slot-scope="scope">
            <el-tag :type="getLogLevelType(scope.row.level)">
              {{ scope.row.level }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="source" label="来源" width="150"></el-table-column>
        <el-table-column prop="message" label="内容"></el-table-column>
      </el-table>
      
      <div class="pagination-container">
        <el-pagination
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="page"
          :page-sizes="[10, 20, 50, 100]"
          :page-size="pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        >
        </el-pagination>
      </div>
    </el-card>
    
    <!-- 清除日志确认对话框 -->
    <el-dialog
      title="清除日志"
      :visible.sync="showClearDialog"
      width="500px"
    >
      <div>
        <p>确定要清除以下范围的日志吗？</p>
        <p v-if="dateRange && dateRange.length === 2">
          时间范围：{{ formatDate(dateRange[0]) }} 至 {{ formatDate(dateRange[1]) }}
        </p>
        <p v-else>
          时间范围：全部
        </p>
        <p>
          日志级别：{{ logLevel ? logLevel : '全部' }}
        </p>
        <div class="warning-text">
          <i class="el-icon-warning"></i>
          <span>此操作不可逆，请谨慎操作！</span>
        </div>
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="showClearDialog = false">取消</el-button>
        <el-button type="danger" @click="clearLogs">确定清除</el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import { formatDate } from '@/utils/format'
import { getSystemLogs, clearSystemLogs } from '@/api/admin'

export default {
  name: 'SystemLogs',
  data() {
    return {
      logs: [],
      loading: false,
      page: 1,
      pageSize: 20,
      total: 0,
      dateRange: null,
      logLevel: '',
      showClearDialog: false,
      pickerOptions: {
        shortcuts: [
          {
            text: '最近一天',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近一周',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 7)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近一个月',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 30)
              picker.$emit('pick', [start, end])
            }
          }
        ]
      }
    }
  },
  created() {
    this.fetchLogs()
  },
  methods: {
    formatDate,
    async fetchLogs() {
      this.loading = true
      try {
        const params = {
          page: this.page - 1,
          size: this.pageSize
        }
        
        if (this.logLevel) {
          params.level = this.logLevel
        }
        
        if (this.dateRange && this.dateRange.length === 2) {
          params.startDate = this.dateRange[0].toISOString()
          params.endDate = this.dateRange[1].toISOString()
        }
        
        const response = await getSystemLogs(params)
        
        if (response && response.data) {
          if (response.data.data && response.data.data.content) {
            this.logs = response.data.data.content.map(log => ({
              ...log,
              timestamp: new Date(log.timestamp)
            }))
            this.total = response.data.data.totalElements || response.data.data.content.length
          } else if (response.data.content && Array.isArray(response.data.content)) {
            this.logs = response.data.content.map(log => ({
              ...log,
              timestamp: new Date(log.timestamp)
            }))
            this.total = response.data.totalElements || response.data.content.length
          } else if (Array.isArray(response.data)) {
            this.logs = response.data.map(log => ({
              ...log,
              timestamp: new Date(log.timestamp)
            }))
            this.total = response.data.length
          } else {
            this.logs = []
            this.total = 0
            console.warn('系统日志数据格式不符合预期', response.data)
          }
        } else {
          this.logs = []
          this.total = 0
        }
      } catch (error) {
        console.error('获取系统日志失败:', error)
        this.$message.error('获取系统日志失败')
        this.logs = []
        this.total = 0
      } finally {
        this.loading = false
      }
    },
    getLogLevelType(level) {
      const types = {
        ERROR: 'danger',
        WARNING: 'warning',
        INFO: 'info',
        DEBUG: 'success'
      }
      return types[level] || 'info'
    },
    handleDateChange() {
      // 日期变化时不自动查询，等用户点击查询按钮
    },
    handleLevelChange() {
      // 级别变化时不自动查询，等用户点击查询按钮
    },
    handleSizeChange(size) {
      this.pageSize = size
      this.fetchLogs()
    },
    handleCurrentChange(page) {
      this.page = page
      this.fetchLogs()
    },
    async clearLogs() {
      try {
        let startDate = null
        let endDate = null
        
        if (this.dateRange && this.dateRange.length === 2) {
          startDate = this.dateRange[0].toISOString()
          endDate = this.dateRange[1].toISOString()
        }
        
        await clearSystemLogs(startDate, endDate)
        this.$message.success('日志清除成功')
        this.showClearDialog = false
        this.fetchLogs() // 重新加载日志
      } catch (error) {
        console.error('清除日志失败:', error)
        this.$message.error('清除日志失败')
      }
    }
  }
}
</script>

